import {createBrowserRouter} from 'react-router';
import App from '../App';
import ToDoList from '../ToDoList/ToDoList';
import Users from '../Users';

const router = createBrowserRouter(
    [
        {
            path: "/",
            element: <App />,
            children: [
                {
                    path: "/about",
                    element: <h1>About</h1>
                },
                {
                    path: "/todo",
                    element: <ToDoList />
                },
                {
                    path: "/users",
                    element: <Users />
                }
            ]
        }
    ]
)

export default router;
